powerpagecomponent.content:
{
  "source": "<style>
    .nav-item.active {
        background-color: #e6f0ff;
        color: #0b5fff;
        font-weight: 600;
    }

    .nav-item.active svg {
        fill: #0b5fff;
    }
</style>

{%include 'Roles'%}
<nav class="topbar topbar--employee">
    <div class="topbar-left">
        <button class="hamburger" id="hbtn" onclick="toggleNav()" aria-label="Toggle menu">
            <span class="bar"></span><span class="bar"></span><span class="bar"></span>
        </button>
        <div class="brand">
            <div class="brand-icon brand-icon--employee">
                <svg viewBox="0 0 16 16">
                    <path
                        d="M8 1a7 7 0 100 14A7 7 0 008 1zm0 3a1.5 1.5 0 110 3 1.5 1.5 0 010-3zm0 8.5c-2 0-3.75-1-4.8-2.5.05-1.6 3.2-2.5 4.8-2.5s4.75.9 4.8 2.5C11.75 11.5 10 12.5 8 12.5z" />
                </svg>
            </div>
            <span class="brand-name">IT Support Portal</span>
        </div>
    </div>
    <div class="user-pill user-pill--employee">
        <div class="user-avatar user-avatar--employee">TT</div>
        <span class="user-name user-name--employee">{{user.fullname}}</span>
    </div>
</nav>

<div class="overlay" id="overlay" onclick="closeNav()"></div>

<aside class="sidenav" id="sidenav">
    <!-- <div class="sidenav-head">
        <div class="sidenav-avatar sidenav-avatar--employee">{{user.fullname}}</div>
        <div>
            <p class="sidenav-username">{{user.fullname}}</p>
            <p class="sidenav-role sidenav-role--employee">Employee</p>
        </div>
    </div> -->
    <div class="nav-scroll">
        {%if isEmployee%}
        <p class="nav-group-label">Main menu</p>
        <a href="/" class="nav-item"><svg viewBox="0 0 16 16">
                <path d="M2 3h5v5H2V3zm0 6h5v5H2V9zm7-6h5v5H9V3zm0 6h5v5H9V9z" />
            </svg>Home</a>
        <a href="/submit" class="nav-item"><svg viewBox="0 0 16 16">
                <path
                    d="M2 3a1 1 0 011-1h10a1 1 0 011 1v9a1 1 0 01-1 1H3a1 1 0 01-1-1V3zm1.5 1v7h9V4h-9zm1 1.5h7v1h-7v-1zm0 2.5h5v1H4.5V8z" />
            </svg>Submit ticket</a>
        <p class="nav-group-label">My tickets</p>
        <a href="/mytickets" class="nav-item"><svg viewBox="0 0 16 16">
                <path d="M8 1a7 7 0 100 14A7 7 0 008 1zm.75 10H7.25V7.25h1.5V11zm0-5.25H7.25v-1.5h1.5v1.5z" />
            </svg>All my tickets<span class="nav-badge nav-badge--blue">4</span></a>
        {%endif%}
        {%if isManager%}
        <p class="nav-group-label">Main menu</p>
        <a href="/manager-dashboard" class="nav-item"><svg viewBox="0 0 16 16">
                <path d="M8 1.5a6.5 6.5 0 100 13 6.5 6.5 0 000-13zM8 4v4.5l3 1.5-.75 1.5L7 9.5V4h1z" />
            </svg>Dashboard</a>
        <a href="/" class="nav-item"><svg viewBox="0 0 16 16">
                <path d="M2 3h5v5H2V3zm0 6h5v5H2V9zm7-6h5v5H9V3zm0 6h5v5H9V9z" />
            </svg>Home</a>
        <a href="/submit" class="nav-item"><svg viewBox="0 0 16 16">
                <path
                    d="M2 3a1 1 0 011-1h10a1 1 0 011 1v9a1 1 0 01-1 1H3a1 1 0 01-1-1V3zm1.5 1v7h9V4h-9zm1 1.5h7v1h-7v-1zm0 2.5h5v1H4.5V8z" />
            </svg>Submit ticket</a>
        <p class="nav-group-label">Tickets Details</p>
        <a href="/mytickets" class="nav-item"><svg viewBox="0 0 16 16">
                <path d="M8 1a7 7 0 100 14A7 7 0 008 1zm.75 10H7.25V7.25h1.5V11zm0-5.25H7.25v-1.5h1.5v1.5z" />
            </svg>My Tickets<span class="nav-badge nav-badge--blue">4</span></a>
        
        <a href="my-tickets.html" class="nav-item"><svg viewBox="0 0 16 16">
                <path
                    d="M8 1a7 7 0 100 14A7 7 0 008 1zm3.03 4.47L7 9.5 5.47 7.97l-1.06 1.06L7 11.62l5.09-5.09-1.06-1.06z" />
            </svg>Resolved</a>
        {%endif%}
    </div>
    <div class="sidenav-footer">
        <a class="logout-btn" href="{% if homeurl %}/{{ homeurl }}{% endif %}{{ website.sign_out_url_substitution }}">
            <svg viewBox="0 0 16 16">
                <path
                    d="M6 2h4a2 2 0 012 2v1h-1.5V4a.5.5 0 00-.5-.5H6a.5.5 0 00-.5.5v8a.5.5 0 00.5.5h4a.5.5 0 00.5-.5v-1H12v1a2 2 0 01-2 2H6a2 2 0 01-2-2V4a2 2 0 012-2zm3.25 5.25H5v1.5h4.25l-1.5 1.5 1.06 1.06L12 8.5l-3.19-3.31-1.06 1.06 1.5 1.5z" />
            </svg>
            Logout
        </a>
    </div>
</aside>

<script>

    function toggleNav() {
        var nav = document.getElementById('sidenav');
        var overlay = document.getElementById('overlay');
        var btn = document.getElementById('hbtn');
        if (nav.classList.contains('open')) {
            closeNav();
        } else {
            nav.classList.add('open');
            overlay.classList.add('visible');
            btn.classList.add('open');
        }
    }

    function closeNav() {
        var nav = document.getElementById('sidenav');
        var overlay = document.getElementById('overlay');
        var btn = document.getElementById('hbtn');
        if (nav) nav.classList.remove('open');
        if (overlay) overlay.classList.remove('visible');
        if (btn) btn.classList.remove('open');
    }

    document.addEventListener('keydown', function (e) {
        if (e.key === 'Escape') closeNav();
    });
    console.log('###', '{{isEmployee}}');

   // $(document).ready(function () {

        const currentPath = window.location.pathname;

        document.querySelectorAll(".nav-item").forEach(link => {
            const linkPath = link.getAttribute("href");

            // Exact match OR child routes
            if (
                linkPath !== "#" &&
                (currentPath === linkPath || currentPath.startsWith(linkPath + "/"))
            ) {
                link.classList.add("active");
            }
        });


   // })



</script>"
}
